pre_capture_js:
() => {
  const form = document.querySelector('otto-web-setup-calculation-engine-params-form');
  if (!form) return;
  // Contraer el contenedor para que no tenga altura fija
  form.style.height = 'auto';
  form.style.minHeight = 'unset';
  form.style.position = 'relative';
  form.style.display = 'flex';
  form.style.flexDirection = 'column';
  // Quitar posicionamiento absoluto del botón de acciones
  const actions = form.querySelector('.actions');
  if (actions) {
    actions.style.position = 'static';
    actions.style.marginTop = '16px';
  }
}
